head.b:skin:
/* ==== RESET ==== */
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
html{scroll-behavior:smooth}
body{font-family:'Inter',sans-serif;background:#050510;color:#f1f5f9;line-height:1.6;overflow-x:hidden;transition:background .3s,color .3s}
a{text-decoration:none;color:inherit}
ul{list-style:none}
::-webkit-scrollbar{width:5px}
::-webkit-scrollbar-track{background:#050510}
::-webkit-scrollbar-thumb{background:#7c3aed;border-radius:99px}

/* ==== VARIABLES ==== */
:root{
  --purple:#7c3aed;--cyan:#06b6d4;--pink:#ec4899;--green:#10b981;
  --surface:rgba(255,255,255,.04);--border:rgba(255,255,255,.08);
  --muted:#94a3b8;--radius:16px;--mono:'JetBrains Mono',monospace;
}
body.light{background:#f8fafc;color:#0f172a}
body.light nav{background:rgba(248,250,252,.9)}
body.light .glass{background:rgba(0,0,0,.03);border-color:rgba(0,0,0,.08)}
body.light .about-fact{background:rgba(0,0,0,.03);border-color:rgba(0,0,0,.08)}

/* ==== HIDE BLOGGER DEFAULT ELEMENTS ==== */
#navbar-iframe,#google-chrome-offline,#cookieChoiceInfo,.blogger-navbar,#Attribution1,.widget.Attribution,.widget.BlogArchive,.widget.Followers,#comments,.comments,.comment-form{display:none!important}

/* ==== THEME TOGGLE ==== */
#ts-toggle{position:fixed;bottom:2rem;right:2rem;z-index:9999;width:52px;height:52px;border-radius:50%;background:linear-gradient(135deg,var(--purple),var(--cyan));border:none;cursor:pointer;color:#fff;display:flex;align-items:center;justify-content:center;font-size:1.2rem;box-shadow:0 4px 20px rgba(124,58,237,.5);transition:.3s}
#ts-toggle:hover{transform:scale(1.1) rotate(15deg);box-shadow:0 8px 30px rgba(124,58,237,.7)}

/* ==== NAV ==== */
#ts-nav{position:fixed;top:0;left:0;right:0;z-index:1000;display:flex;align-items:center;justify-content:space-between;padding:1rem 4rem;background:rgba(5,5,16,.8);backdrop-filter:blur(20px);border-bottom:1px solid var(--border);transition:.3s}
.ts-logo{font-size:1.25rem;font-weight:800;background:linear-gradient(135deg,var(--purple),var(--cyan));-webkit-background-clip:text;-webkit-text-fill-color:transparent}
.ts-links{display:flex;gap:2rem;align-items:center}
.ts-links a{font-size:.875rem;font-weight:500;color:var(--muted);letter-spacing:.5px;text-transform:uppercase;transition:.2s;position:relative}
.ts-links a::after{content:'';position:absolute;bottom:-4px;left:0;right:0;height:2px;background:linear-gradient(90deg,var(--purple),var(--cyan));transform:scaleX(0);transition:.2s}
.ts-links a:hover{color:#f1f5f9}
.ts-links a:hover::after{transform:scaleX(1)}
.ts-cta{padding:.5rem 1.25rem;border:1px solid var(--purple);border-radius:99px;color:var(--purple)!important;font-weight:600!important}
.ts-cta:hover{background:var(--purple);color:#fff!important}
.ts-cta::after{display:none!important}
.ts-burger{display:none;background:none;border:none;color:#f1f5f9;font-size:1.5rem;cursor:pointer}

/* ==== HERO ==== */
#ts-hero{min-height:100vh;display:flex;align-items:center;justify-content:center;padding:8rem 4rem 4rem;text-align:center;position:relative;z-index:2}
.ts-badge{display:inline-flex;align-items:center;gap:.5rem;background:rgba(124,58,237,.15);border:1px solid rgba(124,58,237,.3);border-radius:99px;padding:.4rem 1rem;font-size:.8rem;color:var(--purple);margin-bottom:2rem;animation:fadeUp .6s ease both}
.ts-badge .dot{width:8px;height:8px;background:var(--green);border-radius:50%;animation:pulseDot 2s infinite}
.ts-name{font-size:clamp(3rem,8vw,6rem);font-weight:900;letter-spacing:-3px;line-height:1;margin-bottom:1rem;background:linear-gradient(135deg,#fff 0%,var(--purple) 40%,var(--cyan) 80%,#fff 100%);background-size:200%;-webkit-background-clip:text;-webkit-text-fill-color:transparent;animation:shimmer 4s linear infinite,fadeUp .6s .1s ease both}
.ts-typing{font-family:var(--mono);font-size:1.1rem;color:var(--cyan);margin-bottom:1.5rem;min-height:1.8rem;animation:fadeUp .6s .2s ease both}
.ts-cursor{display:inline-block;width:2px;height:1.1em;background:var(--cyan);margin-left:2px;animation:blink .7s step-end infinite;vertical-align:text-bottom}
.ts-desc{font-size:1.1rem;color:var(--muted);max-width:560px;margin:0 auto 2.5rem;animation:fadeUp .6s .3s ease both}
.ts-btns{display:flex;gap:1rem;justify-content:center;flex-wrap:wrap;animation:fadeUp .6s .4s ease both}
.ts-btn{display:inline-flex;align-items:center;gap:.5rem;padding:.85rem 2rem;border-radius:99px;font-weight:600;font-size:.95rem;transition:.25s;cursor:pointer;border:none}
.ts-btn-p{background:linear-gradient(135deg,var(--purple),var(--cyan));color:#fff;box-shadow:0 0 30px rgba(124,58,237,.4)}
.ts-btn-p:hover{transform:translateY(-2px);box-shadow:0 0 50px rgba(124,58,237,.6)}
.ts-btn-o{background:transparent;border:1px solid var(--border);color:#f1f5f9}
.ts-btn-o:hover{border-color:var(--purple);background:rgba(124,58,237,.1)}
.ts-stats{display:flex;gap:3rem;justify-content:center;margin-top:3rem;animation:fadeUp .6s .5s ease both}
.ts-stat-n{font-size:2rem;font-weight:900;background:linear-gradient(135deg,var(--purple),var(--cyan));-webkit-background-clip:text;-webkit-text-fill-color:transparent}
.ts-stat-l{font-size:.75rem;color:var(--muted);text-transform:uppercase;letter-spacing:1px}
.ts-scroll{margin-top:4rem;display:flex;flex-direction:column;align-items:center;gap:.5rem;color:var(--muted);font-size:.8rem;animation:fadeUp .6s .6s ease both}
.ts-scroll-line{width:1px;height:60px;background:linear-gradient(to bottom,var(--purple),transparent);animation:scrollLine 2s ease-in-out infinite}

/* ==== SECTION BASE ==== */
.ts-section{padding:6rem 4rem;max-width:1200px;margin:0 auto;position:relative;z-index:2}
.ts-tag{display:inline-flex;align-items:center;gap:.5rem;font-family:var(--mono);font-size:.75rem;color:var(--cyan);text-transform:uppercase;letter-spacing:2px;margin-bottom:1rem}
.ts-tag::before{content:'//';opacity:.5}
.ts-h2{font-size:clamp(2rem,4vw,3rem);font-weight:800;letter-spacing:-1px;line-height:1.1;margin-bottom:1rem}
.ts-div{width:60px;height:3px;border-radius:99px;background:linear-gradient(90deg,var(--purple),var(--cyan));margin-bottom:3rem}

/* ==== GLASS ==== */
.glass{background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);backdrop-filter:blur(12px);transition:.3s}
.glass:hover{border-color:rgba(124,58,237,.4);box-shadow:0 0 30px rgba(124,58,237,.1);transform:translateY(-4px)}

/* ==== ABOUT ==== */
.ts-about-grid{display:grid;grid-template-columns:1fr 1fr;gap:4rem;align-items:center}
.ts-avatar-wrap{position:relative;display:flex;justify-content:center}
.ts-avatar{width:280px;height:280px;border-radius:50%;background:linear-gradient(135deg,var(--purple),var(--cyan));display:flex;align-items:center;justify-content:center;font-size:6rem;z-index:1;box-shadow:0 0 60px rgba(124,58,237,.3);animation:float 4s ease-in-out infinite}
.ts-avatar-ring{position:absolute;inset:-8px;border-radius:50%;border:2px solid transparent;background:linear-gradient(#050510,#050510) padding-box,linear-gradient(135deg,var(--purple),var(--cyan)) border-box;animation:rotate 8s linear infinite}
.ts-avatar-ring::after{content:'';position:absolute;width:16px;height:16px;background:var(--cyan);border-radius:50%;top:10px;left:50%;box-shadow:0 0 10px var(--cyan)}
.ts-about-text p{color:var(--muted);margin-bottom:2rem;line-height:1.8}
.ts-facts{display:grid;grid-template-columns:1fr 1fr;gap:1rem;margin-bottom:2rem}
.about-fact{padding:1rem;border-radius:12px;background:var(--surface);border:1px solid var(--border)}
.fact-label{font-size:.75rem;color:var(--muted);text-transform:uppercase;letter-spacing:1px;margin-bottom:.25rem}
.fact-value{font-weight:600}

/* ==== SKILLS ==== */
.ts-skills-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:1.5rem}
.skill-card{padding:1.75rem}
.skill-icon{width:48px;height:48px;border-radius:12px;display:flex;align-items:center;justify-content:center;font-size:1.4rem;margin-bottom:1rem}
.skill-card h3{font-size:1.1rem;font-weight:700;margin-bottom:.5rem}
.skill-card p{font-size:.875rem;color:var(--muted);margin-bottom:1.25rem}
.skill-tags{display:flex;flex-wrap:wrap;gap:.4rem}
.skill-tag{font-size:.75rem;padding:.25rem .75rem;border-radius:99px;background:rgba(255,255,255,.06);border:1px solid var(--border);color:var(--muted)}
.skill-bar-wrap{margin-top:1rem}
.skill-bar-label{display:flex;justify-content:space-between;font-size:.8rem;color:var(--muted);margin-bottom:.4rem}
.skill-bar{height:4px;background:rgba(255,255,255,.08);border-radius:99px;overflow:hidden}
.skill-bar-fill{height:100%;border-radius:99px;background:linear-gradient(90deg,var(--purple),var(--cyan));width:0;transition:width 1.2s cubic-bezier(.4,0,.2,1)}

/* ==== PROJECTS ==== */
.ts-proj-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(320px,1fr));gap:1.5rem}
.proj-card{overflow:hidden}
.proj-thumb{height:180px;display:flex;align-items:center;justify-content:center;font-size:3rem;position:relative;overflow:hidden;transition:.3s}
.proj-card:hover .proj-thumb{transform:scale(1.05)}
.proj-thumb::after{content:'';position:absolute;inset:0;background:linear-gradient(to bottom,transparent 50%,rgba(5,5,16,.9))}
.proj-body{padding:1.5rem}
.proj-tag{font-size:.7rem;font-weight:600;text-transform:uppercase;letter-spacing:1px;color:var(--cyan);margin-bottom:.5rem}
.proj-card h3{font-size:1.1rem;font-weight:700;margin-bottom:.5rem}
.proj-card p{font-size:.875rem;color:var(--muted);margin-bottom:1rem}
.proj-links{display:flex;gap:.75rem}
.proj-link{display:inline-flex;align-items:center;gap:.4rem;font-size:.8rem;font-weight:500;color:var(--muted);padding:.4rem .9rem;border-radius:99px;border:1px solid var(--border);transition:.2s}
.proj-link:hover{border-color:var(--purple);color:var(--purple)}

/* ==== BLOG ==== */
.ts-blog-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(300px,1fr));gap:1.5rem}
.blog-card{padding:1.75rem;display:flex;flex-direction:column}
.blog-date{font-size:.75rem;color:var(--muted);font-family:var(--mono);margin-bottom:.75rem}
.blog-card h3{font-size:1.1rem;font-weight:700;margin-bottom:.75rem;line-height:1.4}
.blog-card h3 a{color:#f1f5f9;transition:.2s}
.blog-card h3 a:hover{color:var(--purple)}
.blog-card p{font-size:.875rem;color:var(--muted);flex:1;margin-bottom:1.25rem}
.blog-more{display:inline-flex;align-items:center;gap:.4rem;font-size:.85rem;font-weight:600;color:var(--purple);transition:.2s}
.blog-more:hover{gap:.75rem}

/* ==== CONTACT ==== */
#ts-contact{text-align:center}
.ts-contact-wrap{max-width:640px;margin:0 auto}
.ts-socials{display:flex;gap:1rem;justify-content:center;flex-wrap:wrap;margin-bottom:3rem}
.soc-link{width:56px;height:56px;border-radius:16px;background:var(--surface);border:1px solid var(--border);display:flex;align-items:center;justify-content:center;font-size:1.4rem;transition:.25s}
.soc-link:hover{transform:translateY(-4px);border-color:var(--purple);box-shadow:0 8px 30px rgba(124,58,237,.3)}
.ts-contact-info{display:flex;gap:2rem;justify-content:center;flex-wrap:wrap;margin-top:2rem}
.ts-contact-item{display:flex;align-items:center;gap:.75rem;color:var(--muted);font-size:.9rem}
.ts-contact-item i{color:var(--purple)}

/* ==== FOOTER ==== */
#ts-footer{border-top:1px solid var(--border);padding:2rem 4rem;display:flex;align-items:center;justify-content:space-between;color:var(--muted);font-size:.85rem;position:relative;z-index:2}

/* ==== REVEAL ==== */
.reveal{opacity:0;transform:translateY(30px);transition:opacity .7s ease,transform .7s ease}
.reveal.on{opacity:1;transform:none}
.reveal-l{opacity:0;transform:translateX(-30px);transition:opacity .7s ease,transform .7s ease}
.reveal-l.on{opacity:1;transform:none}
.reveal-r{opacity:0;transform:translateX(30px);transition:opacity .7s ease,transform .7s ease}
.reveal-r.on{opacity:1;transform:none}

/* ==== KEYFRAMES ==== */
@keyframes fadeUp{from{opacity:0;transform:translateY(20px)}to{opacity:1;transform:translateY(0)}}
@keyframes shimmer{to{background-position:200% center}}
@keyframes pulseDot{0%,100%{opacity:1;transform:scale(1)}50%{opacity:.5;transform:scale(1.3)}}
@keyframes scrollLine{0%,100%{opacity:1;transform:scaleY(1)}50%{opacity:.4;transform:scaleY(.5)}}
@keyframes rotate{to{transform:rotate(360deg)}}
@keyframes blink{0%,100%{opacity:1}50%{opacity:0}}
@keyframes float{0%,100%{transform:translateY(0)}50%{transform:translateY(-10px)}}

/* ==== MOBILE ==== */
@media(max-width:768px){
  #ts-nav{padding:1rem 1.5rem}
  .ts-links{display:none}
  .ts-links.open{display:flex;flex-direction:column;position:fixed;inset:0;background:rgba(5,5,16,.97);justify-content:center;align-items:center;gap:2rem;z-index:999}
  .ts-links.open a{font-size:1.5rem}
  .ts-burger{display:block;z-index:1000}
  .ts-section{padding:4rem 1.5rem}
  .ts-about-grid{grid-template-columns:1fr}
  .ts-avatar{width:200px;height:200px;font-size:4rem}
  .ts-stats{gap:1.5rem}
  #ts-footer{flex-direction:column;gap:1rem;text-align:center;padding:2rem 1.5rem}
}

body.script:
//
/* Canvas particles */
const C=document.getElementById('ts-canvas'),X=C.getContext('2d');
let W,H,P=[];
function rsz(){W=C.width=innerWidth;H=C.height=innerHeight}rsz();addEventListener('resize',rsz);
class Par{constructor(){this.r()}r(){this.x=Math.random()*W;this.y=Math.random()*H;this.s=Math.random()*2+.5;this.vx=(Math.random()-.5)*.3;this.vy=(Math.random()-.5)*.3;this.o=Math.random()*.4+.1;this.h=Math.random()>.5?270:190}u(){this.x+=this.vx;this.y+=this.vy;if(this.x<0||this.x>W||this.y<0||this.y>H)this.r()}d(){X.beginPath();X.arc(this.x,this.y,this.s,0,Math.PI*2);X.fillStyle=`hsla(${this.h},80%,70%,${this.o})`;X.fill()}}
for(let i=0;i<100;i++)P.push(new Par());
function glow(x,y,r,c){const g=X.createRadialGradient(x,y,0,x,y,r);g.addColorStop(0,c);g.addColorStop(1,'transparent');X.fillStyle=g;X.beginPath();X.arc(x,y,r,0,Math.PI*2);X.fill()}
let t=0;
function loop(){X.clearRect(0,0,W,H);t+=.003;
glow(W*.15+Math.sin(t)*60,H*.3+Math.cos(t*.7)*40,300,'rgba(124,58,237,.07)');
glow(W*.8+Math.cos(t*.8)*50,H*.6+Math.sin(t)*60,350,'rgba(6,182,212,.06)');
P.forEach(p=>{p.u();p.d()});requestAnimationFrame(loop)}loop();

/* Typing */
const TXT=['~ No Mercy ~','Web Developer 🚀','UI/UX Designer 🎨','Video Editor 🎬','Social Media 📱'];
let ti=0,ci=0,del=false;const tel=document.getElementById('ts-typed');
function type(){const cur=TXT[ti];if(!del){tel.textContent=cur.slice(0,++ci);if(ci===cur.length){del=true;setTimeout(type,2000);return}}else{tel.textContent=cur.slice(0,--ci);if(ci===0){del=false;ti=(ti+1)%TXT.length}}setTimeout(type,del?60:100)}type();

/* Counters */
function cnt(el,n){let c=0;const s=n/60,t=setInterval(()=>{c=Math.min(c+s,n);el.textContent=Math.floor(c)+'+';if(c>=n)clearInterval(t)},25)}
const co=new IntersectionObserver(e=>{e.forEach(x=>{if(x.isIntersecting){cnt(document.getElementById('c1'),20);cnt(document.getElementById('c2'),50);cnt(document.getElementById('c3'),3);co.disconnect()}})},{threshold:.5});
const hs=document.querySelector('.ts-stats');if(hs)co.observe(hs);

/* Theme */
const tb=document.getElementById('ts-toggle'),ti2=document.getElementById('ts-icon');
if(localStorage.getItem('tst')==='light'){document.body.classList.add('light');ti2.className='fas fa-sun'}
tb.addEventListener('click',()=>{document.body.classList.toggle('light');const l=document.body.classList.contains('light');ti2.className=l?'fas fa-sun':'fas fa-moon';localStorage.setItem('tst',l?'light':'dark')});

/* Reveal */
const ro=new IntersectionObserver(e=>{e.forEach(x=>{if(x.isIntersecting)x.target.classList.add('on')})},{threshold:.1});
document.querySelectorAll('.reveal,.reveal-l,.reveal-r').forEach(el=>ro.observe(el));

/* Skill bars */
const bo=new IntersectionObserver(e=>{e.forEach(x=>{if(x.isIntersecting)x.target.querySelectorAll('.skill-bar-fill').forEach(b=>b.style.width=b.dataset.w+'%')})},{threshold:.3});
document.querySelectorAll('.skill-card').forEach(c=>bo.observe(c));

/* Burger */
const bur=document.getElementById('ts-burger'),lnk=document.getElementById('ts-links');
bur.addEventListener('click',()=>{lnk.classList.toggle('open');bur.innerHTML=lnk.classList.contains('open')?'<i class="fas fa-times"/>':'<i class="fas fa-bars"/>'});
lnk.querySelectorAll('a').forEach(a=>a.addEventListener('click',()=>{lnk.classList.remove('open');bur.innerHTML='<i class="fas fa-bars"/>'}));

/* Nav shrink */
addEventListener('scroll',()=>{document.getElementById('ts-nav').style.padding=scrollY>60?'.6rem 4rem':'1rem 4rem'});
//
